def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -2):
                for b in range(1, a + 4):
                    temp = ((ratio - a) ** 6) / ((a + b) * 1.1 + 1)
                    priority += temp * np.sin(ratio * b / (a + 1)) * np.exp(-0.1 * i)
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 1.7
            if i % 5 == 0:
                priority *= np.log1p(ratio)
            else:
                priority /= np.sqrt(i + 1)
        elif 4 < ratio <= 7:
            for x in range(1, int(np.ceil(ratio)) + 4):
                for y in range(1, x + 4):
                    term = ((ratio - x) ** 4) * np.cos(ratio * y) / (y + 0.7)
                    priority += np.tanh(term) * 1.4
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 3
            mod_factor = sum(np.sin(ratio * (i + n) * 0.9) for n in range(1, 5))
            priority += mod_factor * 0.8
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                power = ((ratio - 2) ** r) / (r * 2.0)
                s += power * np.cos(2 * r * ratio) * np.sin(ratio * 3)
            priority = (s * np.cos(6 * ratio) * np.tanh(i / (bin_cap + 0.5))) - np.log(ratio + 0.1) * 7
            priority += np.tanh(5 * (4 - ratio)) * 2.0
            for p in range(1, 6):
                priority += np.sin(p * ratio * i) * ((ratio - 1.9) ** p) / p
        elif 1.0 <= ratio < 2:
            s = 0
            for m in range(1, 12):
                s += ((2 - ratio) ** m) / (m ** 1.5 + 0.4) * np.cos(m * ratio * 1.5)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.1))
            for n in range(1, 7):
                priority += np.sin(n * ratio * i * 0.8) * ((ratio - 1.0) ** n) / (n + 0.5)
        elif 0.4 <= ratio < 1.0:
            s = 0
            for q in range(1, 20):
                s += ((1.0 - ratio) ** q) / (q * 3.3)
            priority = s
            index_factor = (i + int(item * 1.7)) % 5
            if index_factor == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            elif index_factor == 2:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            else:
                priority += np.sqrt(bin_cap + 1) * 0.7
            for k in range(1, 8):
                priority += ((1.0 - ratio) ** k) * np.sin(k * item * 1.5) * 0.9
        elif 0.15 <= ratio < 0.4:
            s = 0
            for t in range(1, 18):
                s += ((0.4 - ratio) ** t) / (t * 2.7) * np.cos(t * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 6 == 0:
                priority *= 3.0
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for u in range(1, 9):
                priority += ((0.4 - ratio) ** u) / (u * 5.5) * np.cos(item * u * 1.3)
        else:
            s = 0
            for v in range(1, 12):
                s += ((0.15 - ratio) ** v) / (v * 6) * np.sin(v * item * 1.0)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for w in range(1, 10):
                priority += ((0.15 - ratio) ** w) / (w * 8) * np.cos(item * w * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 7
            priority += np.sin(i * ratio * 4) * 1.1
        elif bin_cap > item * 3.0:
            priority -= np.exp(-2.5 * ratio) * 5
            for idx in range(1, 6):
                if (i + idx) % 4 == 0:
                    priority += np.sin(ratio * (i + idx) * 1.2) * 0.5
                else:
                    priority -= np.cos(ratio * (i + idx) * 1.2) * 0.5
        for idx2 in range(1, 6):
            if (i * idx2) % 5 == 0:
                priority += np.sin(ratio * i * idx2) * 0.4
            else:
                priority -= np.cos(ratio * i * idx2) * 0.4
        if i % 4 == 1:
            priority += np.sin(ratio * i * 1.3) * 0.7
        elif i % 4 == 2:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        else:
            priority += np.tanh(ratio * i) * 0.6
        priorities[i] = priority
    return priorities
